// Code node: "Build EE Items"
// Normalises the latest Express Entry round into the shared item shape.
// Dedup is handled downstream by the posted_draws data table.
const src = $input.all();
const round = src.length ? (src[0].json.rounds || [])[0] : null;
if (!round) return [];

const currentDrawNumber = String(round.drawNumber);

const drawNameRaw = round.drawName || round.drawText || 'نامشخص';
const drawName = drawNameRaw.replace(/,?\s*\d{4}-version\s*\d+/i, '').trim();
const drawDate = round.drawDateFull || round.drawDate || 'نامشخص';
const drawSize = round.drawSize || round.drawSizeText || 'نامشخص';
const drawCRS  = round.drawCRS  || round.drawCutOff || round.drawCutoff || round.crs || 'نامشخص';

const categoryMap = [
  { en: 'provincial nominee program',                    fa: 'برنامه نامزدی استانی' },
  { en: 'canadian experience class',                     fa: 'کلاس سابقه کار کانادایی' },
  { en: 'french-language proficiency',                   fa: 'تسلط به زبان فرانسوی' },
  { en: 'french language proficiency',                   fa: 'تسلط به زبان فرانسوی' },
  { en: 'healthcare and social services',                fa: 'مشاغل بهداشت و خدمات اجتماعی' },
  { en: 'healthcare occupations',                        fa: 'مشاغل بهداشت و درمان' },
  { en: 'science, technology, engineering and math',     fa: 'مشاغل علوم، فناوری، مهندسی و ریاضی (STEM)' },
  { en: 'stem occupations',                              fa: 'مشاغل STEM' },
  { en: 'trade occupations',                             fa: 'مشاغل فنی و حرفه‌ای' },
  { en: 'trades occupations',                            fa: 'مشاغل فنی و حرفه‌ای' },
  { en: 'education occupations',                         fa: 'مشاغل آموزشی' },
  { en: 'transport occupations',                         fa: 'مشاغل حمل و نقل' },
  { en: 'agriculture and agri-food',                     fa: 'مشاغل کشاورزی و صنایع غذایی' },
  { en: 'physicians with canadian work experience',      fa: 'پزشکان با سابقه کار کانادایی' },
  { en: 'senior managers with canadian work experience', fa: 'مدیران ارشد با سابقه کار کانادایی' },
  { en: 'researchers with canadian work experience',     fa: 'پژوهشگران با سابقه کار کانادایی' },
  { en: 'skilled military recruits',                     fa: 'سربازان متخصص استخدام شده' },
  { en: 'federal skilled worker',                        fa: 'برنامه فدرال نیروی کار متخصص' },
  { en: 'federal skilled trades',                        fa: 'برنامه فدرال مشاغل فنی' },
  { en: 'general',                                       fa: 'دراو عمومی' },
  { en: 'no program specified',                          fa: 'بدون برنامه مشخص' }
];
function getPersianCategory(englishName) {
  if (!englishName) return 'دسته‌بندی نامشخص';
  const lower = String(englishName).toLowerCase();
  for (const entry of categoryMap) {
    if (lower.includes(entry.en)) return entry.fa;
  }
  return englishName;
}
const drawNameFa = getPersianCategory(drawName);

const link = 'https://www.canada.ca/en/immigration-refugees-citizenship/services/immigrate-canada/express-entry/rounds-invitations.html';
const site = 'www.sugimotovisa.com';

const telegramText = `📢 <b>نتیجه جدیدترین دراو اکسپرس انتری</b>
<b>اقامت دائم کانادا (PR)</b> 🇨🇦

🗓 <b>تاریخ برگزاری:</b> <code>${drawDate}</code>
🎯 <b>دسته‌بندی انتخاب:</b> <b>${drawNameFa}</b>

📊 <b>آمار این دوره:</b>
🔹 تعداد دعوت‌نامه صادر شده: <b>${drawSize}</b> نفر
🔹 حداقل امتیاز قبولی (CRS): <b>${drawCRS}</b> امتیاز

🔗 <a href="${link}">مشاهده جزئیات در سایت رسمی اداره مهاجرت</a>

🌐 ${site}`;

const xPostText = `📢 دراو جدید اکسپرس انتری 🇨🇦
🗓 ${drawDate}
🎯 ${drawNameFa}
🔹 دعوت‌نامه: ${drawSize} نفر
🔹 حداقل CRS: ${drawCRS}
${link}`;

const linkedinText = `📢 نتیجه جدیدترین دراو اکسپرس انتری — اقامت دائم کانادا (PR) 🇨🇦

🗓 تاریخ برگزاری: ${drawDate}
🎯 دسته‌بندی انتخاب: ${drawNameFa}
🔹 تعداد دعوت‌نامه صادر شده: ${drawSize} نفر
🔹 حداقل امتیاز قبولی (CRS): ${drawCRS}

🔗 جزئیات در سایت رسمی اداره مهاجرت:
${link}

🌐 ${site}
#ExpressEntry #مهاجرت_کانادا #اقامت_کانادا #سوگیموتو_ویزا`;

const igCaption = `نتیجه جدیدترین دراو اکسپرس انتری 🇨🇦\n\nتاریخ برگزاری: ${drawDate}\nدسته‌بندی انتخاب: ${drawNameFa}\nتعداد دعوت‌نامه: ${drawSize} نفر\nحداقل امتیاز CRS: ${drawCRS}\n\nبرای مشاوره: ${site}\n\n#اکسپرس_انتری #مهاجرت_کانادا #اقامت_کانادا #سوگیموتو_ویزا #PR #ExpressEntry`;

return [{
  json: {
    program: 'express-entry',
    dedup_key: currentDrawNumber,
    final_post_text: telegramText,
    x_post_text: xPostText,
    linkedin_text: linkedinText,
    ig_caption: igCaption,
    skipInstagram: false,
    // shared story-card fields
    headingLine1: 'آخرین Draw',
    headingLine2: 'اکسپرس انتری',
    headingLine3: 'اقامت دائم کانادا PR',
    statLeftValue: String(drawSize),
    statLeftLabel: 'تعداد دعوتنامه',
    statRightValue: String(drawCRS),
    statRightLabel: 'نمره آخرین نفر قبولی',
    categoryFa: drawNameFa,
    categoryEn: drawName,
    dateText: String(drawDate),
    // data-table meta
    dt_name: drawName,
    dt_crs: String(drawCRS),
    dt_size: String(drawSize)
  }
}];

// Code node: "Build BC PNP Items"
// Emits 0-2 normalised items (Skills and/or Entrepreneur) from the GAS router.
// No staticData dedup — the posted_draws data table handles it downstream.
function esc(s) {
  return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function htmlToPlain(h) {
  return String(h)
    .replace(/<a[^>]*href="([^"]*)"[^>]*>([\s\S]*?)<\/a>/g, '$2: $1')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>');
}
function lowScore(streams) {
  let m = null;
  (streams || []).forEach(function (s) {
    const n = parseInt(String(s.minScore).replace(/[^0-9]/g, ''), 10);
    if (!isNaN(n) && (m === null || n < m)) m = n;
  });
  return m === null ? '—' : String(m);
}
function sumItas(streams) {
  let t = 0;
  (streams || []).forEach(function (s) {
    const n = parseInt(String(s.itas).replace(/[^0-9]/g, ''), 10);
    if (!isNaN(n)) t += n;
  });
  return t;
}

const src = $input.all();
const data = src.length ? src[0].json : null;
if (!data || data.error) return [];

const link = data.sourceUrl;
const site = 'www.sugimotovisa.com';
const outputs = [];

// ===== BC PNP — Skills Immigration =====
const skills = data.skillsImmigration;
if (skills && skills.latestDate) {
  let streamsBlock = '';
  (skills.streams || []).forEach(function (s) {
    const score = s.minScore === 'N/A' ? '—' : esc(s.minScore);
    streamsBlock += '\n🔹 <b>' + esc(s.name) + '</b>\n   • حداقل امتیاز: <b>' + score + '</b>\n   • تعداد دعوت‌نامه: <b>' + esc(s.itas) + '</b> نفر\n';
  });
  const telegram = '📢 <b>نتیجه جدیدترین دراو بی‌سی پی‌ان‌پی</b>\n<b>برنامه نیروی متخصص بریتیش کلمبیا (BC PNP - Skills)</b> 🇨🇦\n\n🗓 <b>تاریخ برگزاری:</b> <code>' + esc(skills.latestDate) + '</code>\n\n📊 <b>خلاصه این دوره:</b>\n🔸 مجموع دعوت‌نامه‌ها: <b>' + esc(skills.totalItas) + '</b> نفر\n' + streamsBlock + '\n🔗 <a href="' + link + '">مشاهده جزئیات در سایت رسمی WelcomeBC</a>\n\n🌐 ' + site;
  const low = lowScore(skills.streams);
  const total = String(skills.totalItas || '—');
  outputs.push({
    json: {
      program: 'bcpnp-skills',
      dedup_key: 'bcpnp-skills::' + skills.latestDate,
      final_post_text: telegram,
      x_post_text: '📢 دراو جدید BC PNP (Skills) 🇨🇦\n🗓 ' + skills.latestDate + '\n🔸 مجموع دعوت‌نامه: ' + total + '\n🔹 حداقل امتیاز: ' + low + '\n' + link,
      linkedin_text: htmlToPlain(telegram) + '\n#BCPNP #مهاجرت_کانادا #بریتیش_کلمبیا #سوگیموتو_ویزا',
      ig_caption: 'نتیجه جدیدترین دراو BC PNP (Skills) 🇨🇦\n\nتاریخ برگزاری: ' + skills.latestDate + '\nمجموع دعوت‌نامه: ' + total + ' نفر\nحداقل امتیاز: ' + low + '\n\nبرای مشاوره: ' + site + '\n\n#BCPNP #بریتیش_کلمبیا #مهاجرت_کانادا #سوگیموتو_ویزا',
      skipInstagram: false,
      headingLine1: 'آخرین Draw',
      headingLine2: 'بریتیش کلمبیا',
      headingLine3: 'BC PNP - Skills',
      statLeftValue: total,
      statLeftLabel: 'مجموع دعوتنامه',
      statRightValue: low,
      statRightLabel: 'حداقل امتیاز',
      categoryFa: 'برنامه نیروی متخصص',
      categoryEn: 'Skills Immigration',
      dateText: String(skills.latestDate),
      dt_name: 'BC PNP Skills',
      dt_crs: low,
      dt_size: total
    }
  });
}

// ===== BC PNP — Entrepreneur Immigration =====
const ent = data.entrepreneurImmigration;
if (ent && ent.latestDate) {
  let streamsBlock = '';
  (ent.streams || []).forEach(function (s) {
    streamsBlock += '\n🔹 <b>' + esc(s.name) + '</b>\n   • حداقل امتیاز: <b>' + esc(s.minScore) + '</b>\n   • تعداد دعوت‌نامه: <b>' + esc(s.itas) + '</b> نفر\n';
  });
  const telegram = '📢 <b>نتیجه جدیدترین دراو کارآفرینی بی‌سی</b>\n<b>برنامه کارآفرینی بریتیش کلمبیا (BC PNP - Entrepreneur)</b> 🇨🇦\n\n🗓 <b>تاریخ برگزاری:</b> <code>' + esc(ent.latestDate) + '</code>\n' + streamsBlock + '\n🔗 <a href="' + link + '">مشاهده جزئیات در سایت رسمی WelcomeBC</a>\n\n🌐 ' + site;
  const low = lowScore(ent.streams);
  const total = sumItas(ent.streams);
  const totalStr = total > 0 ? String(total) : '—';
  outputs.push({
    json: {
      program: 'bcpnp-entrepreneur',
      dedup_key: 'bcpnp-entrepreneur::' + ent.latestDate,
      final_post_text: telegram,
      x_post_text: '📢 دراو جدید کارآفرینی BC PNP 🇨🇦\n🗓 ' + ent.latestDate + '\n🔸 مجموع دعوت‌نامه: ' + totalStr + '\n🔹 حداقل امتیاز: ' + low + '\n' + link,
      linkedin_text: htmlToPlain(telegram) + '\n#BCPNP #Entrepreneur #مهاجرت_کانادا #سوگیموتو_ویزا',
      ig_caption: 'نتیجه جدیدترین دراو کارآفرینی BC PNP 🇨🇦\n\nتاریخ برگزاری: ' + ent.latestDate + '\nمجموع دعوت‌نامه: ' + totalStr + ' نفر\nحداقل امتیاز: ' + low + '\n\nبرای مشاوره: ' + site + '\n\n#BCPNP #Entrepreneur #بریتیش_کلمبیا #سوگیموتو_ویزا',
      skipInstagram: false,
      headingLine1: 'آخرین Draw',
      headingLine2: 'بریتیش کلمبیا',
      headingLine3: 'BC PNP - Entrepreneur',
      statLeftValue: totalStr,
      statLeftLabel: 'مجموع دعوتنامه',
      statRightValue: low,
      statRightLabel: 'حداقل امتیاز',
      categoryFa: 'برنامه کارآفرینی',
      categoryEn: 'Entrepreneur Immigration',
      dateText: String(ent.latestDate),
      dt_name: 'BC PNP Entrepreneur',
      dt_crs: low,
      dt_size: totalStr
    }
  });
}

return outputs;

// Code node: "Build OINP Items"
// Emits 0-2 normalised items (draw summary and/or program update) from the GAS router.
function esc(s) {
  return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function htmlToPlain(h) {
  return String(h)
    .replace(/<a[^>]*href="([^"]*)"[^>]*>([\s\S]*?)<\/a>/g, '$2: $1')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>');
}

const src = $input.all();
const data = src.length ? src[0].json : null;
if (!data || data.error || !data.latestDate || !data.items || data.items.length === 0) return [];

const link = data.sourceUrl;
const site = 'www.sugimotovisa.com';
const outputs = [];
const draws = data.items.filter(function (i) { return i.type === 'draw'; });
const updates = data.items.filter(function (i) { return i.type === 'update'; });

// ===== OINP — Draw summary =====
if (draws.length > 0) {
  let drawsBlock = '';
  let totalItas = 0;
  draws.forEach(function (d) {
    const itaLine = d.itas ? '   • تعداد دعوت‌نامه: <b>' + esc(d.itas) + '</b> نفر\n' : '';
    drawsBlock += '\n🔹 <b>' + esc(d.title) + '</b>\n' + itaLine;
    if (d.itas) { const n = parseInt(d.itas, 10); if (!isNaN(n)) totalItas += n; }
  });
  const totalLine = totalItas > 0 ? '🔸 مجموع دعوت‌نامه‌ها: <b>' + totalItas + '</b> نفر\n' : '';
  const telegram = '📢 <b>نتیجه جدیدترین دراو انتاریو (OINP)</b>\n<b>برنامه مهاجرت استانی انتاریو</b> 🇨🇦\n\n🗓 <b>تاریخ برگزاری:</b> <code>' + esc(data.latestDate) + '</code>\n\n📊 <b>خلاصه این دوره:</b>\n' + totalLine + drawsBlock + '\n🔗 <a href="' + link + '">مشاهده جزئیات در سایت رسمی انتاریو</a>\n\n🌐 ' + site;
  const totalStr = totalItas > 0 ? String(totalItas) : '—';
  const firstTitle = String(draws[0].title || 'OINP').substring(0, 40);
  outputs.push({
    json: {
      program: 'oinp-draw',
      dedup_key: 'oinp-draw::' + data.latestDate + '::' + firstTitle,
      final_post_text: telegram,
      x_post_text: '📢 دراو جدید انتاریو (OINP) 🇨🇦\n🗓 ' + data.latestDate + '\n🔸 مجموع دعوت‌نامه: ' + totalStr + '\n' + link,
      linkedin_text: htmlToPlain(telegram) + '\n#OINP #Ontario #مهاجرت_کانادا #سوگیموتو_ویزا',
      ig_caption: 'نتیجه جدیدترین دراو انتاریو (OINP) 🇨🇦\n\nتاریخ برگزاری: ' + data.latestDate + '\nمجموع دعوت‌نامه: ' + totalStr + ' نفر\n\nبرای مشاوره: ' + site + '\n\n#OINP #انتاریو #مهاجرت_کانادا #سوگیموتو_ویزا',
      skipInstagram: false,
      headingLine1: 'آخرین Draw',
      headingLine2: 'انتاریو OINP',
      headingLine3: 'مهاجرت استانی',
      statLeftValue: totalStr,
      statLeftLabel: 'تعداد دعوتنامه',
      statRightValue: '—',
      statRightLabel: 'حداقل امتیاز',
      categoryFa: 'مهاجرت استانی انتاریو',
      categoryEn: firstTitle,
      dateText: String(data.latestDate),
      dt_name: 'OINP Draw',
      dt_crs: '',
      dt_size: totalStr
    }
  });
}

// ===== OINP — Program update / announcement (no story image) =====
if (updates.length > 0) {
  let updatesBlock = '';
  updates.forEach(function (u) {
    const summaryRaw = (u.summary && u.summary.length > 300) ? u.summary.substring(0, 300) + '...' : (u.summary || '');
    updatesBlock += '\n🔸 <b>' + esc(u.title) + '</b>\n' + esc(summaryRaw) + '\n';
  });
  const telegram = '📣 <b>اطلاعیه مهم برنامه OINP انتاریو</b>\n<b>تغییرات و به‌روزرسانی‌های جدید</b> 🇨🇦\n\n🗓 <b>تاریخ اطلاعیه:</b> <code>' + esc(data.latestDate) + '</code>\n' + updatesBlock + '\n⚠️ <i>این اطلاعیه شامل تغییرات مهم برنامه است، لطفاً برای جزئیات کامل به سایت رسمی مراجعه کنید.</i>\n\n🔗 <a href="' + link + '">مطالعه متن کامل در سایت رسمی انتاریو</a>\n\n🌐 ' + site;
  const firstTitle = String(updates[0].title || 'OINP Update').substring(0, 40);
  outputs.push({
    json: {
      program: 'oinp-update',
      dedup_key: 'oinp-update::' + data.latestDate + '::' + firstTitle,
      final_post_text: telegram,
      x_post_text: '📣 اطلاعیه جدید برنامه OINP انتاریو 🇨🇦\n🗓 ' + data.latestDate + '\n' + firstTitle + '\n' + link,
      linkedin_text: htmlToPlain(telegram) + '\n#OINP #Ontario #مهاجرت_کانادا #سوگیموتو_ویزا',
      ig_caption: '',
      skipInstagram: true,
      headingLine1: '',
      headingLine2: '',
      headingLine3: '',
      statLeftValue: '',
      statLeftLabel: '',
      statRightValue: '',
      statRightLabel: '',
      categoryFa: '',
      categoryEn: '',
      dateText: String(data.latestDate),
      dt_name: 'OINP Update',
      dt_crs: '',
      dt_size: ''
    }
  });
}

return outputs;

// Code node: "Build Alberta Items"
// Parses the Alberta AAIP "Draw information" HTML table (fetched directly from
// alberta.ca as text) and emits the newest draws as normalised items. Dedup is
// handled by the posted_draws data table, so we emit the top few candidates and
// let the table decide which are actually new.
function esc(s) { return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
function stripTags(h) {
  return String(h)
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&#8211;|&ndash;/g, '–').replace(/&#39;|&rsquo;/g, "'")
    .replace(/\s+/g, ' ').trim();
}
function toISO(s) {
  const t = Date.parse(s);
  if (isNaN(t)) return '';
  const d = new Date(t);
  const m = ('0' + (d.getMonth() + 1)).slice(-2);
  const day = ('0' + d.getDate()).slice(-2);
  return d.getFullYear() + '-' + m + '-' + day;
}

const src = $input.all();
const first = src.length ? src[0].json : null;
// httpRequest (responseFormat: text) puts the body in `data`; fall back to body/string.
const html = first ? (first.data || first.body || (typeof first === 'string' ? first : '')) : '';
if (!html) return [];

// Isolate rows whose first cell is a date — that uniquely identifies the draw table.
const dateRe = /^[A-Z][a-z]+ \d{1,2},\s*20\d{2}$/;
const draws = [];
const trRe = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
let tr;
while ((tr = trRe.exec(html)) !== null) {
  const cells = [];
  const tdRe = /<td[^>]*>([\s\S]*?)<\/td>/gi;
  let td;
  while ((td = tdRe.exec(tr[1])) !== null) cells.push(stripTags(td[1]));
  if (cells.length !== 4) continue;
  const date = cells[0];
  if (!dateRe.test(date)) continue;
  draws.push({ date: date, dateISO: toISO(date), stream: cells[1], score: cells[2], invitations: cells[3] });
}
if (!draws.length) return [];

const link = 'https://www.alberta.ca/aaip-processing-information';
const site = 'www.sugimotovisa.com';
const CANDIDATES = 3; // newest N; dedup keeps only the genuinely new ones

return draws.slice(0, CANDIDATES).map(function (d) {
  const streamShort = String(d.stream).substring(0, 50);
  const invCard = String(d.invitations).replace(/less than 10/i, '<10');
  const telegram = '📢 <b>نتیجه جدیدترین دراو آلبرتا (AAIP)</b>\n<b>برنامه مهاجرت استانی آلبرتا</b> 🇨🇦\n\n🗓 <b>تاریخ برگزاری:</b> <code>' + esc(d.date) + '</code>\n🎯 <b>دسته‌بندی:</b> <b>' + esc(d.stream) + '</b>\n\n📊 <b>آمار این دوره:</b>\n🔹 تعداد دعوت‌نامه: <b>' + esc(d.invitations) + '</b>\n🔹 حداقل امتیاز: <b>' + esc(d.score) + '</b>\n\n🔗 <a href="' + link + '">مشاهده جزئیات در سایت رسمی آلبرتا</a>\n\n🌐 ' + site;
  return {
    json: {
      program: 'alberta-aaip',
